import{_ as a,o,c as i,ag as r}from"./chunks/framework.PErH1-Uo.js";const u=JSON.parse('{"title":"🌐 Conversión de una dirección IP privada IPv4 a IPv6","description":"","frontmatter":{},"headers":[],"relativePath":"redes/ipv6/ipv4_a_ipv6_conversion.md","filePath":"redes/ipv6/ipv4_a_ipv6_conversion.md","lastUpdated":1775646765000}'),d={name:"redes/ipv6/ipv4_a_ipv6_conversion.md"};function n(t,e,c,s,p,l){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="🌐-conversion-de-una-direccion-ip-privada-ipv4-a-ipv6" tabindex="-1">🌐 Conversión de una dirección IP privada IPv4 a IPv6 <a class="header-anchor" href="#🌐-conversion-de-una-direccion-ip-privada-ipv4-a-ipv6" aria-label="Permalink to &quot;🌐 Conversión de una dirección IP privada IPv4 a IPv6&quot;">​</a></h1><p>Convertir una dirección IPv4 privada a una dirección IPv6 no es una simple traducción, pero existen formas estandarizadas de <strong>representar direcciones IPv4 dentro del espacio IPv6</strong>. Aquí explicamos las más comunes.</p><hr><h2 id="🛠️-metodos-comunes-de-conversion-o-representacion" tabindex="-1">🛠️ Métodos comunes de conversión o representación <a class="header-anchor" href="#🛠️-metodos-comunes-de-conversion-o-representacion" aria-label="Permalink to &quot;🛠️ Métodos comunes de conversión o representación&quot;">​</a></h2><h3 id="🔹-1-direccion-ipv4-mapeada-en-ipv6" tabindex="-1">🔹 1. Dirección IPv4-mapeada en IPv6 <a class="header-anchor" href="#🔹-1-direccion-ipv4-mapeada-en-ipv6" aria-label="Permalink to &quot;🔹 1. Dirección IPv4-mapeada en IPv6&quot;">​</a></h3><p>Se utiliza el prefijo <code>::ffff:</code> seguido de la dirección IPv4.</p><p><strong>Ejemplo:</strong></p><ul><li>IPv4: <code>192.168.1.1</code></li><li>IPv6 mapeada: <code>::ffff:192.168.1.1</code></li></ul><p>Se convierte a binario la direccion IPv4 y transformamos a hexadecimal cogiendo grupos de 4 bits:</p><p><strong>Ejemplo:</strong><br><code>192.168.1.1</code> en binario es: <code>11000000.10101000.00000001.00000001</code></p><p>Pasamos a Headecimal: <code>1100 -&gt; C, 0000 -&gt; 0, 1010 -&gt; A, 0001 -&gt; 1, 0000 -&gt; 0, 0001 -&gt; 1, 0000 -&gt; 0</code>.<br> resultado: <code>C0A1:0101</code></p><p><strong>Equivalente hexadecimal:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>::ffff:c0a8:0101</span></span></code></pre></div><p>📌 <strong>Uso</strong>:</p><ul><li>Para compatibilidad con IPv4 en sistemas dual-stack.</li><li>No es enrutable en redes IPv6 puras.</li><li>Utilizado por aplicaciones o sistemas operativos.</li></ul><hr><h3 id="🔹-2-conversion-manual-con-prefijo-local-fd00-8" tabindex="-1">🔹 2. Conversión manual con prefijo local <code>fd00::/8</code> <a class="header-anchor" href="#🔹-2-conversion-manual-con-prefijo-local-fd00-8" aria-label="Permalink to &quot;🔹 2. Conversión manual con prefijo local `fd00::/8`&quot;">​</a></h3><p>Puedes usar el prefijo reservado <code>fd00::/8</code> (para redes internas) y codificar la IPv4 en hexadecimal.</p><p><strong>Ejemplo:</strong></p><ul><li>IPv4: <code>192.168.0.10</code> → Hex: <code>c0a8:000a</code></li><li>IPv6 resultante: <code>fd00::c0a8:000a</code></li></ul><p>✅ Útil en redes privadas para representar direcciones IPv4 en formato IPv6.</p><hr><h3 id="🔹-3-metodo-6rd-ipv6-rapid-deployment" tabindex="-1">🔹 3. Método 6rd (IPv6 Rapid Deployment) <a class="header-anchor" href="#🔹-3-metodo-6rd-ipv6-rapid-deployment" aria-label="Permalink to &quot;🔹 3. Método 6rd (IPv6 Rapid Deployment)&quot;">​</a></h3><p>Encapsula una IPv4 dentro de un prefijo IPv6 asignado por el ISP.</p><p><strong>Ejemplo:</strong></p><ul><li>Prefijo ISP: <code>2001:db8::/32</code></li><li>IPv4: <code>192.0.2.33</code> = <code>c000:0221</code></li><li>Resultado IPv6: <code>2001:db8:c000:0221::/64</code></li></ul><p>📌 Este método requiere configuración específica por parte del proveedor de servicios.</p><hr><h2 id="✅-resumen" tabindex="-1">✅ Resumen <a class="header-anchor" href="#✅-resumen" aria-label="Permalink to &quot;✅ Resumen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Método</th><th>Ejemplo IPv6</th><th>Usos</th></tr></thead><tbody><tr><td>IPv4-mapped</td><td><code>::ffff:192.168.1.1</code></td><td>Sistemas dual-stack</td></tr><tr><td>Prefijo local (fd00:😃</td><td><code>fd00::c0a8:000a</code></td><td>Redes privadas, transición</td></tr><tr><td>6rd (con prefijo ISP)</td><td><code>2001:db8:c0a8:000a::/64</code></td><td>Implementaciones específicas ISP</td></tr></tbody></table><hr><p>🧠 <strong>Nota</strong>: Estas representaciones no cambian el protocolo IP subyacente, sino que permiten coexistencia y transición entre IPv4 e IPv6.</p>',32)])])}const m=a(d,[["render",n]]);export{u as __pageData,m as default};
